class Solution {
public:
    string largestPalindrome(int n, int k) {
        if (n == 1) {
            for (int i = 9; i >= 0; --i) {
                if (i % k == 0) return to_string(i);
            }
        }

        string res(n, '9');
        for (int i = pow(10, n - 1); i < pow(10, n); ++i) {
            if (i % k == 0) {
                string str = to_string(i);
                string rev = str;
                reverse(rev.begin(), rev.end());
                if (str == rev) {
                    res = str;
                    break;
                }
            }
        }
        return res;
    }
};
